23	{
24	    /*
25	     * Basic Bit-Reversal Scheme:
26	     *
27	     * The incrementing pattern operations used here correspond
28	     * to the logic operations of a synchronous counter.
29	     *
30	     * Incrementing a binary number simply flips a sequence of
31	     * least-significant bits, for example from 0111 to 1000.
32	     * So in order to compute the next bit-reversed index, we
33	     * have to flip a sequence of most-significant bits.
34	     */
35	
36	    unsigned N = 1 << log2_N;   /* N */
37	    unsigned Nd2 = N >> 1;      /* N/2 = number range midpoint */
38	    unsigned Nm1 = N - 1;       /* N-1 = digit mask */
39	    unsigned i;                 /* index for source element */
40	    unsigned j;                 /* index for next destination element */
41	
42	    for (i = 0, j = 0; i < N; i++) {
43	        dst[j] = src[i];
44	
45	        /*
46	         * Find least significant zero bit
47	         */
48	
49	        unsigned lszb = ~i & (i + 1);
50	
51	        /*
52	         * Use division to bit-reverse the single bit so that we now have
53	         * the most significant zero bit
54	         *
55	         * N = 2^r = 2^(m+1)
56	         * Nd2 = N/2 = 2^m
57	         * if lszb = 2^k, where k is within the range of 0...m, then
58	         *     mszb = Nd2 / lszb
59	         *          = 2^m / 2^k
60	         *          = 2^(m-k)
61	         *          = bit-reversed value of lszb
62	         */
63	
64	        unsigned mszb = Nd2 / lszb;
65	
66	        /*
67	         * Toggle bits with bit-reverse mask
68	         */
69	
70	        unsigned bits = Nm1 & ~(mszb - 1);
71	        j ^= bits;
72	    }
