136	void ffti_evaluate_f(complex_f data[], unsigned log2_N, fft_dir direction)
137	{
138	    /*
139	     * In-place FFT butterfly algorithm
140	     *
141	     * input:
142	     *     A[] = array of N shuffled complex values where N is a power of 2
143	     * output:
144	     *     A[] = the DFT of input A[]
145	     *
146	     * for r = 1 to log2(N)
147	     *     m = 2^r
148	     *     Wm = exp(−j2π/m)
149	     *     for n = 0 to N-1 by m
150	     *         Wmk = 1
151	     *         for k = 0 to m/2 - 1
152	     *             u = A[n + k]
153	     *             t = Wmk * A[n + k + m/2]
154	     *             A[n + k]       = u + t
155	     *             A[n + k + m/2] = u - t
156	     *             Wmk = Wmk * Wm
157	     *
158	     * For inverse FFT, use Wm = exp(+j2π/m)
159	     */
160	
161	    unsigned N;
162	    unsigned r;
163	    unsigned m, md2;
164	    unsigned n, k;
165	    unsigned i_e, i_o;
166	    double theta_2pi;
167	    double theta;       /* Use double for precision */
168	    complex_d Wm, Wmk;  /* Use double for precision */
169	    complex_d u, t;     /* Use double for precision */
170	
171	    N = 1 << log2_N;
172	    theta_2pi = (direction == FFT_FORWARD) ? -M_PI : M_PI;
173	    theta_2pi *= 2;
174	
175	    for (r = 1; r <= log2_N; r++)
176	    {
177	        m = 1 << r;
178	        md2 = m >> 1;
179	        theta = theta_2pi / m;
180	        Wm.re = cos(theta);
181	        Wm.im = sin(theta);
182	        for (n = 0; n < N; n += m)
183	        {
184	            Wmk.re = 1.f;
185	            Wmk.im = 0.f;
186	            for (k = 0; k < md2; k++)
187	            {
188	                i_e = n + k;
189	                i_o = i_e + md2;
190	                u.re = data[i_e].re;
191	                u.im = data[i_e].im;
192	                t.re = complex_mul_re(Wmk.re, Wmk.im, data[i_o].re, data[i_o].im);
193	                t.im = complex_mul_im(Wmk.re, Wmk.im, data[i_o].re, data[i_o].im);
194	                data[i_e].re = u.re + t.re;
195	                data[i_e].im = u.im + t.im;
196	                data[i_o].re = u.re - t.re;
197	                data[i_o].im = u.im - t.im;
198	                t.re = complex_mul_re(Wmk.re, Wmk.im, Wm.re, Wm.im);
199	                t.im = complex_mul_im(Wmk.re, Wmk.im, Wm.re, Wm.im);
200	                Wmk = t;
201	            }
202	        }
203	    }
204	}
