212	void fftr_f(complex_f data[], unsigned log2_N, fft_dir direction)
213	{
214	    /*
215	     * fft(A[], N):
216	     *     if N == 1
217	     *         return
218	     *     for k = 0 to N/2-1
219	     *         e[k] = A[2*k]
220	     *         o[k] = A[2*k+1]
221	     *     fft(e, N/2)
222	     *     fft(o, N/2);
223	     *     WN = exp(−j2π/N)
224	     *     WNk = 1
225	     *     for k = 0 to N/2-1
226	     *         A[k]     = e[k] + WNk * o[k]
227	     *         A[k+N/2] = e[k] - WNk * o[k]
228	     *         WNk = WNk * WN
229	     *
230	     * For inverse FFT, use Wm = exp(+j2π/N)
231	     */
232	
233	    if (log2_N > 0)
234	    {
235	        unsigned log2_Nd2;
236	        unsigned Nd2;
237	        unsigned k;
238	        unsigned kpNd2;
239	        complex_f *evn, *odd;
240	        double theta_pi;
241	        double theta;       /* Use double for precision */
242	        complex_d WN, WNk;  /* Use double for precision */
243	        complex_d u, t;     /* Use double for precision */
244	
245	        log2_Nd2 = log2_N - 1;
246	        Nd2 = 1 << log2_Nd2;
247	
248	        evn = malloc(Nd2 * sizeof(complex_f));
249	        odd = malloc(Nd2 * sizeof(complex_f));
250	
251	        for (k = 0; k < Nd2; k++)
252	        {
253	            evn[k] = data[2*k];
254	            odd[k] = data[2*k+1];
255	        }
256	
257	        fftr_f(evn, log2_Nd2, direction);
258	        fftr_f(odd, log2_Nd2, direction);
259	
260	        theta_pi = (direction == FFT_FORWARD) ? -M_PI : M_PI;
261	        theta = theta_pi / Nd2;  /* - (2 * M_PI) / N */
262	        WN.re = cos(theta);
263	        WN.im = sin(theta);
264	
265	        WNk.re = 1.f;
266	        WNk.im = 0.f;
267	        for (k = 0; k < Nd2; k++)
268	        {
269	            kpNd2 = k + Nd2;
270	
271	            u.re = evn[k].re;
272	            u.im = evn[k].im;
273	            t.re = complex_mul_re(WNk.re, WNk.im, odd[k].re, odd[k].im);
274	            t.im = complex_mul_im(WNk.re, WNk.im, odd[k].re, odd[k].im);
275	            data[k].re = u.re + t.re;
276	            data[k].im = u.im + t.im;
277	            data[kpNd2].re = u.re - t.re;
278	            data[kpNd2].im = u.im - t.im;
279	
280	            t.re = complex_mul_re(WNk.re, WNk.im, WN.re, WN.im);
281	            t.im = complex_mul_im(WNk.re, WNk.im, WN.re, WN.im);
282	            WNk = t;
283	        }
284	
285	        free(evn);
286	        free(odd);
287	    }
288	}
